const QUALIFIER_ROWS=document.querySelectorAll("tr.qualifier-row"),HEAD_TO_HEAD_ROWS=document.querySelectorAll("tr.head-to-head-row");function filterAllRows(e){QUALIFIER_ROWS.forEach(t=>{const n=t.dataset.athleteName;t.hidden=n!==e}),HEAD_TO_HEAD_ROWS.forEach(t=>{const n=t.querySelectorAll("td[data-athlete-name]");if(n.length!==2){t.hidden=!1;return}const s=n[0].dataset.athleteName,o=n[1].dataset.athleteName,i=s!==e&&o!==e;t.hidden=i})}function removeFilterAllRows(){QUALIFIER_ROWS.forEach(e=>{e.hidden=!1}),HEAD_TO_HEAD_ROWS.forEach(e=>{e.hidden=!1})}function onClickFilter(e,t){const n=e.dataset.athleteName;t?filterAllRows(n):removeFilterAllRows()}QUALIFIER_ROWS.forEach(e=>{const t=e.querySelector("td.filter-chip"),n=t.querySelector("input");n.addEventListener("change",t=>{const n=t.target.checked;onClickFilter(e,n)})})